namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.Add(new(NextId(), "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new(NextId(), "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new(NextId(), "New feature: dark mode is now available.", DateTime.UtcNow.AddMinutes(-2)));
    }

    /// <summary>Returns all notifications ordered newest-first.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.OrderByDescending(n => n.Timestamp).ToList();
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications
                .Where(n => n.Id > sinceId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
        }
    }

    /// <summary>Simulates an external system pushing a new notification.</summary>
    public void AddRandom()
    {
        string[] templates =
        [
            "Server CPU usage exceeded 80%.",
            "Deployment to production completed.",
            "A new user signed up.",
            "Scheduled backup finished.",
            "Payment received from customer #42.",
            "Disk space warning on node-3.",
            "SSL certificate expires in 7 days.",
        ];

        var message = templates[Random.Shared.Next(templates.Length)];

        lock (_lock)
        {
            _notifications.Add(new(NextId(), message, DateTime.UtcNow));
        }
    }

    private int NextId() => _nextId++;
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorNotifications.Services
@inject NotificationService Svc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted ms-3 text-nowrap">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    // Runs during both SSR and interactive — loads initial data for fast first paint.
    protected override void OnInitialized()
    {
        _notifications = Svc.GetAll();
    }

    // Runs only once after the component becomes interactive in the browser.
    // During static SSR this is never called, so the polling loop cannot leak.
    protected override void OnAfterRender(bool firstRender)
    {
        if (!firstRender) return;

        _cts = new CancellationTokenSource();
        _ = PollForNotificationsAsync(_cts.Token);
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        // Determine the high-water mark so we don't re-fetch what we already have.
        var lastSeenId = _notifications.Count > 0
            ? _notifications.Max(n => n.Id)
            : 0;

        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            // Simulate external activity so there's something new to poll.
            Svc.AddRandom();

            var newer = Svc.GetSince(lastSeenId);
            if (newer.Count > 0)
            {
                lastSeenId = newer.Max(n => n.Id);
                _notifications.InsertRange(0, newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

