namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.Add(new(NextId(), "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new(NextId(), "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new(NextId(), "New feature: dark mode is now available.", DateTime.UtcNow.AddMinutes(-2)));
    }

    /// <summary>Returns all notifications ordered newest-first.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.OrderByDescending(n => n.Timestamp).ToList();
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications
                .Where(n => n.Id > sinceId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
        }
    }

    /// <summary>Simulates an external system pushing a new notification.</summary>
    public void AddRandom()
    {
        string[] templates =
        [
            "Server CPU usage exceeded 80%.",
            "Deployment to production completed.",
            "A new user signed up.",
            "Scheduled backup finished.",
            "Payment received from customer #42.",
            "Disk space warning on node-3.",
            "SSL certificate expires in 7 days.",
        ];

        var message = templates[Random.Shared.Next(templates.Length)];

        lock (_lock)
        {
            _notifications.Add(new(NextId(), message, DateTime.UtcNow));
        }
    }

    private int NextId() => _nextId++;
}

